# ============================================================
#  setup_repo.ps1  -  one-shot setup for Skyblock-Mod-Migrator
#
#  Run this from INSIDE your cloned repo folder, e.g.:
#     cd C:\Users\jaxse\Skyblock-Mod-Migrator
#     powershell -ExecutionPolicy Bypass -File .\setup_repo.ps1
#
#  It writes every project file (exact bytes, verified), then
#  commits and pushes to GitHub. On the first push, Git
#  Credential Manager opens a GitHub login in your browser -
#  that part is you; this script never handles a password.
# ============================================================
$ErrorActionPreference = 'Stop'

# Sanity check: are we in a git repo?
if (-not (Test-Path '.git')) {
    Write-Host 'ERROR: no .git folder here. cd into your cloned Skyblock-Mod-Migrator folder first.' -ForegroundColor Red
    exit 1
}

# path -> base64(file bytes). Decoded to disk exactly, so code with
# quotes/backticks/special chars and the PNG all transfer perfectly.
$files = [ordered]@{
  '.github/workflows/build.yml' = ''
  '.gitignore' = 'ZGlzdC8KYnVpbGQvCiouc3BlYwpfX3B5Y2FjaGVfXy8KKi5weWMKbWlncmF0ZWRfbW9kcy8K'
  'LICENSE' = ''
  'README.md' = ''
  'build_linux.sh' = ''
  'build_macos.command' = ''
  'build_windows.bat' = ''
  'iexpress/BuildModMigrator.sed' = ''
  'iexpress/README.md' = ''
  'iexpress/build_windows.bat' = ''
  'iexpress/make_exe_with_iexpress.bat' = ''
  'iexpress/mod_migrator_gui.py' = ''
  'migrate_mods.py' = ''
  'mod_migrator_gui.py' = ''
  'screenshots/app-screenshot.png' = ''
}

# Expected SHA-256 per file, to verify nothing got mangled.
$expected = [ordered]@{
  '.github/workflows/build.yml' = 'cd3e50a03bc398371025c21e2f42a73f2b63935487acdd29fc92faea4434593d'
  '.gitignore' = '06ce160e0cf9c5bc4bc9b5b3b742c5cbf5806e229ea59487a2dabd828f5d981e'
  'LICENSE' = '1713f26cc2aa99bb41b30f26ab68b0e8fcd2c7c4f03cd41e6b3ddcd0ce675c1b'
  'README.md' = '78cd068beb5e8b45c4821d793900c4c760f336b56ad4f208dd603d0c036019db'
  'build_linux.sh' = '69b14170309dd3ffd5ea144ca64e0dc36e0ea7ea4754ce280881dc7536b2ec66'
  'build_macos.command' = 'e13aa0644c3c21ce3b2189350e70942070cfba76d45f8d6224af7fde68954ab1'
  'build_windows.bat' = '3d6324c01a4b085f965b42e44e3e6ec8aaa74661853b23a8ec89e20dac576e34'
  'iexpress/BuildModMigrator.sed' = '309f99914c965df8e21568bfd0b030697959a815c4354de0d58f8bf4c4f29c41'
  'iexpress/README.md' = 'ef9ce70db39c06498ccec7b3a1c79c8bbe1594a6108ccf9f4aaf090dd6f4095f'
  'iexpress/build_windows.bat' = '3d6324c01a4b085f965b42e44e3e6ec8aaa74661853b23a8ec89e20dac576e34'
  'iexpress/make_exe_with_iexpress.bat' = '714246dbadfe49cfef703b27c84ae195af8816a618f4ed8a9dcb9253b649ebde'
  'iexpress/mod_migrator_gui.py' = '802eac715cfac97b67e81d2af706c2a9fe6f67dbc15b1cb4fe2384d4f222ee39'
  'migrate_mods.py' = 'd6fe7d025af37315fb5fd6de34bc29d5f6e6fdbe994fc1dc4ff53d6b91b635a9'
  'mod_migrator_gui.py' = '802eac715cfac97b67e81d2af706c2a9fe6f67dbc15b1cb4fe2384d4f222ee39'
  'screenshots/app-screenshot.png' = 'bc30718f4a3662867f41247bf004b81b2260595ad7db5d722ab05fe633b44a0e'
}

foreach ($rel in $files.Keys) {
    $full = Join-Path (Get-Location) $rel
    $dir = Split-Path $full -Parent
    if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    [System.IO.File]::WriteAllBytes($full, [Convert]::FromBase64String($files[$rel]))
    $h = (Get-FileHash $full -Algorithm SHA256).Hash.ToLower()
    if ($h -ne $expected[$rel]) {
        Write-Host "CHECKSUM MISMATCH on $rel - aborting." -ForegroundColor Red
        exit 1
    }
    Write-Host "  ok  $rel" -ForegroundColor Green
}

Write-Host ''
Write-Host 'All files written and checksum-verified.' -ForegroundColor Cyan

# Clean up the leftover transfer folder from the earlier attempt, if present
$chunks = Join-Path (Split-Path (Get-Location) -Parent) '_mm_chunks'
if (Test-Path $chunks) { Remove-Item -Recurse -Force $chunks; Write-Host 'Removed leftover _mm_chunks folder.' }

# Set a local commit identity if none is configured (does not touch global git config)
$haveName = (git config user.name)
if (-not $haveName) {
    git config user.name 'icantcodeyet'
    git config user.email 'icantcodeyet@users.noreply.github.com'
    Write-Host 'Set local commit identity to icantcodeyet (change later with: git config user.email ...).'
}

git add -A
Write-Host ''
Write-Host 'Staged changes:' -ForegroundColor Cyan
git status --short

git commit -m 'Add Mod Migrator GUI app, builders, CI workflow, and IExpress packaging'
git branch -M main
Write-Host ''
Write-Host 'Pushing to GitHub (a browser login may open on first push)...' -ForegroundColor Cyan
git push -u origin main
Write-Host ''
Write-Host 'Done. View it at: https://github.com/icantcodeyet/Skyblock-Mod-Migrator' -ForegroundColor Green
